var API_BASE = 'https://nishinae.store'; var body = document.body ? document.body.innerText : ''; var KEYWORDS = /zus|chagee|tealive|kfc|coffee bean|cbtl|gigi|winrar/i; var orderRe = /Order\s*ID\s*[:\-]?\s*([A-Z0-9]{10,})/gi; 

// Find all order matches with their positions
var orderMatches = [];
var m;
while ((m = orderRe.exec(body)) !== null) {
  orderMatches.push({ id: m[1], index: m.index });
}

if (orderMatches.length === 0) { return 'NO_ORDERS_FOUND'; }

var debugInfo = [];
var orders = [];

for (var i = 0; i < orderMatches.length; i++) {
  var sid = orderMatches[i].id;
  var start = orderMatches[i].index;
  var end = i + 1 < orderMatches.length ? orderMatches[i + 1].index : body.length;
  var section = body.substring(start, Math.min(body.length, end));

  // Debug: store first 500 chars of section
  debugInfo.push('=== Order ' + sid + ' ===');
  debugInfo.push('Section start: ' + start + ', end: ' + end);

  var lines = section.split(/[\n\r]+/).map(function(l){ return l.trim(); }).filter(function(l){ return l.length > 0; });

  debugInfo.push('Lines found: ' + lines.length);

  var items = [];
  for (var j = 0; j < lines.length; j++) {
    var line = lines[j];

    // Check for inline quantity format: Product Name xN
    var inlineQty = line.match(/(.+?)\s+x(\d+)\b/i);
    if (inlineQty && KEYWORDS.test(inlineQty[1])) {
      items.push({ productName: inlineQty[1].trim(), quantity: parseInt(inlineQty[2], 10) });
      debugInfo.push('  [INLINE] Line ' + j + ': "' + line.substring(0,30) + '..." -> qty=' + parseInt(inlineQty[2], 10));
      continue;
    }

    // Check if line itself is a product keyword
    if (KEYWORDS.test(line) && line.length > 8) {
      var qty = 1;
      var nextLine = j + 1 < lines.length ? lines[j + 1] : '';

      // Check for standalone quantity on next line
      var standaloneQty = nextLine.match(/^x(\d+)$/i);
      if (standaloneQty) {
        qty = parseInt(standaloneQty[1], 10);
        j++;
        debugInfo.push('  [STANDALONE] Line ' + j + ': "' + line.substring(0,30) + '..." + next="' + nextLine + '" -> qty=' + qty);
      } else {
        // Check for trailing quantity in same line
        var trailingQty = line.match(/x(\d+)\b/i);
        if (trailingQty) {
          qty = parseInt(trailingQty[1], 10);
          debugInfo.push('  [TRAILING] Line ' + j + ': "' + line.substring(0,30) + '..." -> qty=' + qty);
        } else {
          debugInfo.push('  [NO QTY] Line ' + j + ': "' + line.substring(0,30) + '..." -> qty=1');
        }
      }

      // Check for duplicates
      var alreadyAdded = false;
      for (var k = 0; k < items.length; k++) {
        if (items[k].productName.trim() === line.trim()) {
          items[k].quantity += qty;
          alreadyAdded = true;
          debugInfo.push('    -> MERGED with existing, new qty=' + items[k].quantity);
          break;
        }
      }
      if (!alreadyAdded) {
        items.push({ productName: line.trim(), quantity: qty });
        debugInfo.push('    -> ADDED new item: ' + line.trim() + ' x' + qty);
      }
    }
  }

  debugInfo.push('Items for ' + sid + ': ' + JSON.stringify(items));

  if (items.length > 0) {
    orders.push({ shopeeOrderId: sid, items: items });
  }
}

return JSON.stringify({ debug: debugInfo, orders: orders }, null, 2);
